<template><div class="studio"><div class="top"><div><h2>{{room.title||'直播课堂'}}</h2><span>{{room.course_name}} · {{statusText}}</span></div><div><el-button @click="toggleCamera">{{cameraOn?'关闭摄像头':'开启摄像头'}}</el-button><el-button @click="toggleMic">{{micOn?'静音':'开启麦克风'}}</el-button><el-button v-if="room.status==='live'" type="danger" @click="finish">结束直播</el-button></div></div><el-alert v-if="error" :title="error" type="error"/>
<div class="layout"><section><div id="local-video" class="video"><div v-if="!connected" class="hint">正在准备 TRTC 直播画面…</div></div><div class="stats">♥ {{room.like_count||0}} 点赞　{{messages.length}} 条评论</div></section><aside><el-tabs><el-tab-pane label="互动聊天"><div class="messages"><p v-for="m in messages" :key="m.interaction_id"><b>{{m.display_name||m.username}}：</b>{{m.content}}</p></div><div class="send"><el-input v-model="text" maxlength="500" @keyup.enter="send"/><el-button @click="send">发送</el-button></div></el-tab-pane><el-tab-pane :label="`连麦申请 ${pending.length}`"><div v-for="m in pending" :key="m.request_id" class="request"><span>{{m.real_name}}</span><el-button type="success" link @click="decide(m,true)">同意</el-button><el-button type="danger" link @click="decide(m,false)">拒绝</el-button></div></el-tab-pane></el-tabs></aside></div></div></template>
<script setup>import{ref,computed,onMounted,onBeforeUnmount}from'vue';import{useRoute,useRouter}from'vue-router';import{ElMessage,ElMessageBox}from'element-plus';import{roomDetail,startRoom,endRoom,sendComment,handleMic}from'../../api/live';import{useLiveRtc}from'../../composables/useLiveRtc';const route=useRoute(),router=useRouter(),id=route.params.roomId,room=ref({}),messages=ref([]),requests=ref([]),text=ref(''),socket=ref();const{connected,cameraOn,micOn,error,join,leave,toggleCamera,toggleMic}=useLiveRtc(id,'teacher');const pending=computed(()=>requests.value.filter(x=>x.status==='pending')),statusText=computed(()=>({live:'直播中',scheduled:'未开始',ended:'已结束'}[room.value.status]||''));async function refresh(){room.value=await roomDetail(id);messages.value=room.value.interactions||[];requests.value=room.value.micRequests||[]}function ws(){const base=(location.protocol==='https:'?'wss':'ws')+'://'+location.host;socket.value=new WebSocket(`${base}/ws/live?roomId=${encodeURIComponent(id)}&token=${encodeURIComponent(localStorage.getItem('token'))}`);socket.value.onmessage=()=>refresh()}async function send(){if(!text.value.trim())return;await sendComment(id,text.value);text.value='';socket.value?.send(JSON.stringify({type:'refresh'}));refresh()}async function decide(m,v){await handleMic(id,m.request_id,v);socket.value?.send(JSON.stringify({type:'mic'}));refresh()}async function finish(){await ElMessageBox.confirm('确定结束直播？结束后无法再次开播。','提示');await leave();await endRoom(id);ElMessage.success('直播已结束');router.push('/teacher/live')}onMounted(async()=>{await refresh();if(route.query.start==='1'&&room.value.status==='scheduled'){await startRoom(id);await refresh()}if(room.value.status==='live'){try{await join()}catch(e){error.value=e.message}}ws()});onBeforeUnmount(()=>{socket.value?.close();leave()})</script>
<style scoped>.studio{background:#fff;padding:20px;border-radius:16px}.top,.layout,.send,.request{display:flex;justify-content:space-between;gap:14px}.top{align-items:center;margin-bottom:16px}.top span{color:#64748b}.layout section{flex:1}.video{aspect-ratio:16/9;background:#101827;border-radius:12px;overflow:hidden;color:#fff;display:flex;align-items:center;justify-content:center}.layout aside{width:360px;border:1px solid #e5e7eb;padding:14px;border-radius:12px}.messages{height:390px;overflow:auto}.messages p{word-break:break-word}.stats{padding:12px}.request{padding:10px 0;border-bottom:1px solid #eee}@media(max-width:900px){.layout{display:block}.layout aside{width:auto;margin-top:14px}}</style>
